package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.ApiResponse;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.operations.*;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.web.bind.annotation.*;import java.time.OffsetDateTime;
@RestController @RequestMapping("/internal/supplier/v1/operations/events")public class OperationsEventOpenApiController{private final OperationsEventConsumerApplicationService service;public OperationsEventOpenApiController(OperationsEventConsumerApplicationService service){this.service=service;}@PostMapping public ApiResponse<Void> consume(@Valid @RequestBody Request b,HttpServletRequest r){String source=r.getHeader("X-Source-System"),code=r.getHeader("X-Event-Code");if(source==null||code==null)throw new BusinessException(ErrorCode.VALIDATION_FAILED,"缺少事件请求头");service.consume(new OperationsEvent(source,code,b.eventType(),b.supplierId(),b.businessType(),b.businessId(),b.businessNo(),b.message(),b.dueAt(),b.occurredAt()==null?OffsetDateTime.now():b.occurredAt()));return ApiResponse.success(null,r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}public record Request(@NotBlank String eventType,@Positive long supplierId,@NotBlank String businessType,@Positive long businessId,String businessNo,@NotBlank String message,OffsetDateTime dueAt,OffsetDateTime occurredAt){} }
